mapper.select:
SELECT e.id, e.registration_id, e.patient_id, p.patient_name,
       e.exam_type, e.exam_name, e.result, e.fee, e.status, e.exam_time
FROM examination e
LEFT JOIN patient p ON e.patient_id = p.id

    AND e.registration_id = #{registrationId}
    AND e.patient_id = #{patientId}
    AND e.registration_id IN (SELECT r.id FROM registration r WHERE r.doctor_id = #{doctorId})
    AND e.status = #{status}

ORDER BY e.exam_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM examination e

    AND e.registration_id = #{registrationId}
    AND e.patient_id = #{patientId}
    AND e.registration_id IN (SELECT r.id FROM registration r WHERE r.doctor_id = #{doctorId})
    AND e.status = #{status}
